INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989350","title":"Дэдпул. Том 5. Что происходит в Вегасе","author":"Дэниел Уэй,Карло Барбери","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002137579/140/4ea6/__Dedpul._Tom_5._Chto_proishodit_v_Vegase.jpg","isbn":"978-5-91339-463-78","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Выходные в Вегасе в стиле Дэдпула — это куча взрывов, третьесортные злодеи и ограбление казино, которым гордился бы сам Джордж Клуни! Взяв за горло болтливого владельца клуба, Дэдпул вызывает гнев боссов самых крупных казино Лас-Вегаса и их нового наёмного защитника, Казино–охранника в разномастном суперкостюме, вооружённого до зубов, у которого с человеком в красном и чёрном есть свои счёты. Дело в том, что человек в костюме — не кто иной, как…  Здесь мы тебе этого не расскажем, лоботряс! Прочитай книгу, чтобы узнать, кто восстал из прошлого Дэдпула, чтобы надрать ему задницу, и как Дэдпул нашёл себе постоянную работу! Без шуток.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999184,"hdCover":""},{"id":"098934f","title":"Что Если Веном завладел бы Дэдпулом?","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002188070/140/08b8/Rik_Remender__Chto_Esli_Venom_zavladel_by_Dedpulom.jpg","isbn":"978-5-9909387-3-1","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Встречайте, легендарные Веном и Дэдпул в одном выпуске! Они были созданы в одну эпоху, но при этом являются полными противоположностями. Изначально единственной целью Венома было съесть мозги Человека-Паука, но теперь ему повстречался Дэдпул, который годами доказывал нам, что мозгов у него нет.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999183,"hdCover":""},{"id":"098934e","title":"Дэдпул. Том 4. Дэдпул против З.А.Щ.И.Т.Ы","author":"Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002229821/140/c7d4/Dzherri_Daggan_Brajan_Posen__Dedpul._Tom_4._Dedpul_protiv_Z.A.Sch.I.T.Y.jpg","isbn":"978-5-91339-457-1","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул единолично объявляет войну международному миротворческому агентству. Но вдобавок к маниакальному наемнику, страждущему расплаты, З.А.Щ.И.Т.А. узнает, что в их ряды затесался предатель – и похоже, что это Агент Престон! Дэдпул прилетает на Авианосец, намереваясь любым способом получить свои деньги… и в итоге сталкивается лицом к лицу с Агентом Филом Колсоном! Какая жалость, что Колсон – фанат Кэпа. А также: очередное путешествие прямиком в тайное прошлое Дэдпула, в котором Болтливый Наемник начнет сеять хаос космических масштабов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999182,"hdCover":""},{"id":"098934d","title":"Дэдпул. Том 3. Хороший, плохой, злой","author":"Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002076542/140/b959/Dzherri_Daggan_Brajan_Posen__Dedpul._Tom_3._Horoshij_plohoj_zloj.jpg","isbn":"978-5-91339-459-0","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"УМОРИТЕЛЬНОЕ, БЕЗУДЕРЖНОЕ ПЕРЕЛОПАЧИВАНИЕ ИСТОРИИ БОЛТЛИВОГО НАЁМНИКА ОТ ДЖЕРРИ ДАГГАНА И БРАЙАНА ПОСЕНА ПРОДОЛЖАЕТСЯ!  А начинается всё с одного из забытых приключений Дэдпула прямиком из тусовых 70-х, когда он патрулировал улицы с Силачом и Железным Кулаком! Но неожиданно противник Трио по Найму появился в нашем времени, и теперь Дэдпул должен найти своих старых друзей, дабы вновь дать ему бой! Затем возвращается прошлое Дэдпула, а именно программа «Оружие Икс». По этой причине он приходит к товарищам по «Оружию Плюс», не желающим помогать ему, — Росомахе и Капитану Америка!  Находясь прямо в лапах врага, эта троица погружается всё глубже в тайны, окутывающие это место. но когда герои поймут, что нечто, случившееся с Дэдпулом в прошлом,привело к созданию множества других оружий, успеют ли они вовремя устранить грядущую угрозу?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999181,"hdCover":""},{"id":"098934c","title":"Дэдпул. Том 1. Мертвые президенты","author":"Тони Мур,Джерри Дагган, Брайан Посен","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001488756/140/a07e/__Dedpul._Tom_1._Mertvye_prezidenty.jpg","isbn":"978-5-91339-354-8","publisher":"Комильфо","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Команда мёртвых американских президентов — начиная от Вашингтона, и заканчивая Фордом — была поднята из могил и начала терроризировать своих сограждан. Величайшие герои Marvel не могли позволить открыто охотиться на американских патриотов, подставив собственный имидж под удар. Лишь человек, обладающий уже вконец запятнанной репутацией, по сути своей являющийся вооружённым до зубов безумцем, способен справиться со столь отвратительным заданием. Но кто во вселенной Marvel станет пачкать руки, убивая глав государства? Пришло время Дэдпула!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999180,"hdCover":""},{"id":"098934b","title":"Ночь живого Дэдпула","author":"Каллен Банн,Рамон Росаньес","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001550460/140/46e3/__Noch_zhivogo_Dedpula.jpg","isbn":"978-5-91339-384-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Дэдпул очнулся от сытой комы и понял, что Нью-Йорк захватили полоумные зомби! И им не особо-то нравится вся эта жажда человеческой плоти. Съедят ли Болтливого Наёмника болтливые зомби? Вас повергнет в ужас один только вид этого отвратительного гниющего монстра, бродящего по округе... а про зомби, с которыми он дерётся, мы вообще молчим! (Дошло? Типа первая часть была про самого Дэдпула. Почему бы не добавить в хоррор-комикс про зомби немного юмора?)  Каллен Банн, автор сценария полюбившихся многим \"Уничтожительных приключений Дэдпула\", расскажет вам самую мрачную историю из когда-либо написанных... и мы так говорим не потому, что она будет чёрно-белой (и красной)! Мы вас предупредили, друзья! Так что звоните в гонг и запирайте дверь на засов - Дэдпул вышел на охоту за нежитью.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999179,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098934a","title":"Отряд Икс. Книга 1","author":"Рик Ремендер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002041984/140/eee0/Rik_Remender__Otryad_Iks._Kniga_1.jpg","isbn":"978-5-9908127-3-4","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Росомаха, Псайлок, Архангел, Дэдпул и Фантомекс. Вместе они - Отряд Икс, мутанты с лицензией на убийство. Их первое задание: расправиться с ужасным Апокалипсисом, переродившимся в теле невинного ребенка. Пока Отряд Икс пытается смириться со своими решениями, из будущего прибывают киборги Дэтлоки с поразительно знакомыми лицами... их цель - казнить Фантомекса! Но и это ещё не все - ведь затем Архангел раскрывает свою сущность и продолжает дело Апокалипсиса, потому ради его спасения Отряд Икс отправляется в другую реальность: Эру Апокалипсиса! Победа Темного Ангела ознаменует конец всей жизни на Земле, но сможет ли даже команда заматерелых убийц покончить со своим товарищем?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4.5,"review":"","added":9999178,"hdCover":""},{"id":"0989349","title":"Скотт Пилигрим против вселенной","author":"Брайан Ли О''Мэлли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003227367/140/6b20/Brajan_Li_O039Melli__Skott_Piligrim_protiv_vselennoj.jpg","isbn":"978-5-91339-674-7","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Скотт Пилигрим","genres":["Комиксы","манга","графические романы"],"annotation":"Скотт готов к лету, но расслабляться ему некогда.  Скотт Пилигрим отметил двадцать четвертый день рождения, но следующего может и не быть. Ему пора сразиться с двумя злыми бывшими Рамоны - да, с двумя сразу - и они натравили на Скотта роботов! Неважно, портят ли они вечеринку Джули или срывают первый концерт Sex Bobomb за несколько месяцев, Скотту надо с ними разобраться. Но получится ли у него победить злых роботов и не испортить отношения с Рамоной? Успеет ли он победить её злых бывших до того, как Рамона - О БОЖЕ - его бросит? Ответы на эти вопросы Скотт найдёт внутри книги... если выживет!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999177,"hdCover":""},{"id":"0989348","title":"Говард Утка. Том 0. Какого гуся","author":"Чип Здарски","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001489464/140/0af3/Chip_Zdarski__Govard_Utka._Tom_0._Kakogo_gusya.jpg","isbn":"978-5-91339-355-5","publisher":"Комильфо, Marvel Worldwide","pubDate":"2015","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Говард Утка вернулся! Станьте свидетелем того, как он берётся за странные дела, которые способен раскрыть лишь частный детектив вселенной Marvel... если, конечно, он говорящая утка! Первое дело Говарда начинается со встречи с Чёрной Кошкой, а заканчивается в космосе, в руках Коллекционера! Но он не один. Его сокамерник - Реактивный Енот! Смогут ли эти двое антропоморфных животных изменить ход игры и вырваться на свободу?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999176,"hdCover":""},{"id":"0989347","title":"Человек-Паук 2099. Том 1. Вне времени","author":"Питер Дэвид,Рик Леонарди","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002533811/140/ce75/__ChelovekPauk_2099._Tom_1._Vne_vremeni.jpg","isbn":"978-5-9909387-9-3","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"В 2099 году Мигель О’Хара получил паучьи способности в результате сорванного эксперимента в лаборатории “Алкемакс”, злобной корпорации, которая пыталась создать супер-солдат. Мигель боролся с компанией с тех самых пор, как узнал об их истинных мотивах, пока не застрял в настоящем! Но здесь, “Алкемакс”, зловещая корпорация из будущего, только начинает свой путь, и у Мигеля есть шанс остановить ее разложение прежде, чем оно успеет начаться! Однако Человек-Паук 2099 вскоре узнает, что он не единственный, кто надеется на лучшее завтра. Когда из-за непростого соглашения с “Алкемакс” Мигель оказывается на территории военных действий, ему приходится сражаться за жизнь своего деда… Переживая нападение Скорпиона и появление охотящегося на пауков Морлана, Мигель оказывается на грани столкновения с Паучьими Мирами! Присоединяйтесь к создателям Человека-Паука 2099 Питеру Дэвиду и Рику Леонарди, а также художнику Уиллу Слайни (Совершенный Человек-Паук: Работа в команде) в самом захватывающем приключении, которое только можно найти по эту сторону 22-го века!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999175,"hdCover":""},{"id":"0989346","title":"Что если? Гражданская война","author":"Larry Stroman,Дэвид Хайн,Эд Брубейкер,Марко Джурджевич,Грег Пак,Кристос Гейдж,Пол Тобин,Кевин Гревье,Рафа Сандовал,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002425226/140/cb6a/__Chto_esli_Grazhdanskaya_vojna.jpg","isbn":"978-5-9909387-5-5","publisher":"Другое издательство","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":2,"review":"","added":9999174,"hdCover":""},{"id":"0989345","title":"Львы Багдада","author":"Брайан К. Вон,Нико Анришон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572232/140/f03d/__Lvy_Bagdada.jpg","isbn":"978-5-389-10060-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"В апреле 2003 года прайд львов выбрался из  Багдадского зоопарка во время бомбардировки города американцами.  Растерянные и голодные, но наконец свободные,  четыре гигантские кошки скитаются по безлюдным улицам Багдада, отчаянно сражаясь за жизнь.  Вдохновленные реальными событиями, писатель Брайан К. Вон и художник Нико Анришон открыли необыкновенное окно в жизнь природы во время войны и показали цену выживания на фоне поразительно правдоподобной истории войны в Ираке. Описывая бедствия, свалившиеся на багдадских львов, эта непростая история затрагивает саму суть понятия «свобода». Можно ли получить ее из чужих рук, или ее можно добыть лишь собственными силами и самопожертвованием?  «Vertigo» и «DC Comics» с гордостью представляют совершенно новое люксовое издание высоко оцененного критиками графического романа, содержащее дополнительные материалы из ранее не издававшихся текста и рисунков от создателей «Львов Багдада».","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999173,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989344","title":"Тёмные мстители. Полное издание","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002904118/140/c0d9/Brajan_Majkl_Bendis__Tjomnye_mstiteli._Polnoe_izdanie.jpg","isbn":"978-5-04-098493-0","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Герои Marvel (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"Выпускайте плохишей! Вот и они, новая команда Величайших Героев Земли, — лучи солнца освещают их улыбающиеся лица, а восторженная толпа готова скандировать их имена, пока те выходят на сцену! Человек-Паук, Росомаха, Мисс Марвел, Хоукай — вы их знаете, вы их любите! Это ваши Мстители, и они здесь, чтобы защитить вас! Только… всё не то, чем кажется. Если настоящие Мстители в подполье, то кто же эти герои, так похожие на них? Почему их собрали? Тёмное Правление только началось, а Тёмные Мстители уже попали в эпицентр безумных планов Нормана Озборна на вселенную Marvel! В сборнике: \"Тёмные Мстители\" #1–6, #9–16 и Ежегодник #1. Автор сценария Брайан Майкл Бендис, художники Майк Деодато, Грег Хорн и Крис Бачало.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999172,"hdCover":""},{"id":"0989343","title":"Удивительный Человек-Паук. Заговор Клонов","author":"Кристос Гейдж,Дэн Слотт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002879549/140/3ff5/__Udivitelnyj_ChelovekPauk._Zagovor_Klonov.jpg","isbn":"978-5-04-098201-1","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"В названии книги есть эмоции","genres":["Комиксы","манга","графические романы"],"annotation":"СМЕРТИ БОЛЬШЕ НЕТ! БУДУЧИ ЧЕЛОВЕКОМ ПАУКОМ, Питер Паркер потерял многих — любимых, друзей и даже врагов. Но что случится, если те, по кому он скорбил, вдруг восстанут из могил? Вы узнаете это, когда он встретится с близкими, которых уже и не мечтал увидеть вновь — равно как и с опасными врагами, которых он предпочёл бы считать мёртвыми. Потому что на каждую Гвен Стейси найдётся Доктор Осьминог! Гений, стоящий за этими воскрешениями — злодей, что уже однажды клонировал Человека-Паука: безумный Шакал! И пока команда героев в лице Шёлк, Мародёра и Алого Паука пытается что-то предпринять, Паучок сталкивается с самой большой проблемой в своей жизни. Если Шакал победит смерть, будет ли жизнь прежней?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3.5,"review":"","added":9999171,"hdCover":""},{"id":"0989342","title":"Грут","author":"Джефф Лавнесс,Брайан Кесинджер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002607868/140/6d24/__Grut.jpg","isbn":"978-5-9909878-3-8","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сольные приключения самого удивительного Стража Галактики! Когда загадочные наемники похищают Реактивного Енота, его лучший друг Грут спешит на помощь. И всем, кто встанет на его пути можно не позавидовать. Тем более что пусть Стражи в комиксе не появляютя, других специальных гостей полно - и в том числе сам Серебряный Серфер!  Законченная история, которую можно читать независимо от других комиксов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999170,"hdCover":""},{"id":"0989341","title":"Супермен. Земля-1. Книга 1","author":"Джей Майкл Стражински,Шэйн Дэвис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000658831/140/e4d2/__Supermen._Zemlya1._Kniga_1.jpg","isbn":"978-5-389-05144-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2013","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Кларк Кент не такой, как все. Он умеет летать. Видит сквозь стены. Испепеляет взглядом. Он — бог среди смертных. Но он одинок и не понимает, в чем его предназначение.  Как и большинство двадцатилетних, он не знает, как распорядиться своей судьбой. Выбрать он может все, что угодно: спорт, науку, финансы или СМИ. Все будет подвластно ему... главное — скрывать от остальных, кто он такой и на что способен.  Но когда небо потемнеет от кораблей, прилетевших с далеких планет и само существование Земли окажется под угрозой, Кларку придется принять самое важное в его жизни решение: раскрыться миру, пожертвовав шансом на нормальную жизнь... или остаться в тени, бросив мир на верную погибель.  Сценарист Дж. Майкл Стражински пересказывает на современный лад историю об уцелевшем одиночке с планеты Криптон и о его битве за спасение человечества с теми, кто был повинен в уничтожении его родного мира. Вместе с художником Шейном Дэвисом («Зеленый фонарь») Стражински покажет вам такого Супермена, какого вы еще не видели!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":4,"review":"","added":9999169,"hdCover":""},{"id":"0989340","title":"Танос. Начало","author":"Джейсон Аарон,Симоне Бьянки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002000114/140/1be6/__Tanos._Nachalo.jpg","isbn":"978-5-9908126-2-8","publisher":"Jellyfish Jam","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Лорд Танос, безумный титан, по праву считается одним из величайших злодеев вселенной Marvel. Но откуда он родом? Как прошло его детство? Что сделало его тем, кем он стал - могущественным покровителем смерти и разрушения? И, что самое важное, каковы его мотивы? Все ответы - в этом комиксе! Перед вами - история трагедии, лжи и судьбоносного жребия. история того, как Танос, воплощение космической кары, пришёл к власти в роли несравненного злодея. Реки крови прольются во имя истинной любви на том пути, что изменит не только жизнь одного мальчика, но и судьбу всей галактики - и даже самой вселенной Marvel!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2018","rating":3,"review":"","added":9999168,"hdCover":""},{"id":"098933f","title":"Ходячие мертвецы. Полное собрание. Том 2","author":"Роберт Киркман, Чарли Адлард, Клифф Ратбёрн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002855048/140/68bb/Robert_Kirkman_Charli_Adlard_Kliff_Ratbjorn__Hodyachie_mertvetsy._Polnoe_sobrani.jpg","isbn":"978-5-91339-698-3","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое? Давно ли кто-то из нас действительно нуждался в том, что постоянно хочет? Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришёл мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мёртвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-10","rating":5,"review":"","added":9999167,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098933e","title":"Бэтмен. Долгий Хэллоуин","author":"Джеф Лоэб","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001434828/140/8eab/Dzhef_Loeb__Betmen._Dolgij_Hellouin.jpg","isbn":"978-5-389-08859-7","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Происходящий во времена первых шагов Бэтмена на дороге борьбы с преступностью «Долгий Хэллоуин» повествует о загадочном убийце по прозвищу Праздник, отмечающем красные даты календаря кровью очередной жертвы. Работая бок о бок с комиссаром полиции Джеймсом Гордоном и окружным прокурором Харви Дентом, Бэтмен пытается предотвратить очередное преступление, но это все равно что пытаться обогнать время. Закрученный сюжет заставляет читателя постоянно гадать, кто же этот таинственный злодей, подозрения падают и на врагов, и на друзей Бэтмена. Описав полный круг, история замкнется. Кто-то умрет, а кто-то изменится навсегда...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-10","rating":5,"review":"","added":9999166,"hdCover":""},{"id":"098933d","title":"Лига Справедливости. Война Троицы","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001912212/140/ffbc/Dzheff_Dzhons__Liga_Spravedlivosti._Vojna_Troitsy.jpg","isbn":"978-5-389-11202-5","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Много веков назад ничего не подозревающая девушка наткнулась на зловещий артефакт: шкатулку в виде трехглазого черепа. Она открыла ее... и на свет вырвались Семь Смертных Грехов.  Тысячелетия спустя Шкатулка Пандоры вновь становится источником многих бед. Перед ее разрушительной силой не способен устоять даже Супермен. Укротить эту силу способен лишь тот, чья душа совершенно чиста, либо же тот, чья душа полностью погрязла во зле. Три загадочных существа бродят по свету в поисках ответов. Три команды героев сойдутся в схватке, в которой решится судьба мира. А в тени зла таится еще более великое зло...  «Лига Справедливости. Война Троицы» объединяет величайшие таланты индустрии комиксов. В создании принимали участие такие звезды как Джефф Джонс, Джефф Лемир, Рэй Фокс, Иван Рейс, Дуг Манки, Микель Ханин и другие — для того, чтобы поведать нам историю о мифах, магии и противостоянии, которое изменит мир New 52 навсегда!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-08","rating":4,"review":"","added":9999165,"hdCover":""},{"id":"098933c","title":"Лига справедливости. Книга 2. Путь злодея (сборник)","author":"Джефф Джонс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001420425/140/93c2/Dzheff_Dzhons__Liga_spravedlivosti._Kniga_2._Put_zlodeya_sbornik.jpg","isbn":"978-5-389-09801-5","publisher":"Азбука","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Лига Справедливости – величайшая сила на стороне добра, какую когда-либо видел мир. Но так считают не все. Их нескончаемая битва со злом приводит к жертвам – жертвам среди мирного населения. Как ни старается Лига уберечь невинные жизни, герои не могут спасти всех. Величайшие победы преданных защитников Земли несут в себе и семена сокрушительных поражений. Ведь горе и испытания рождают не только героев, такой же путь проходят и злодеи.  К самой популярной по версии «Нью-Йорк Таймс» команде в лице Джеффа Джонса и Джима Ли присоединились художники Джин Ха и Карлос д’Анда, и в результате появилась «Лига Справедливости: Путь злодея», куда вошли выпуски серии с седьмого по двенадцатый.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-08","rating":4.5,"review":"","added":9999164,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098933b","title":"Бэтмен. Темная победа","author":"Джефф Лоэб,Тим Сейл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002036557/140/f955/__Betmen._Temnaya_pobeda.jpg","isbn":"978-5-389-10782-3","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"На заре своей карьеры Темный Рыцарь пытается выследить неуловимого убийцу копов по кличке Палач, прежде чем тот нанесет очередной удар. Единственный намек на личность преступника — листок с детской игрой, приколотый к телам жертв. В качестве главных подозреваемых выступает целая галерея злодеев: Двуликий, Джокер, Загадочник, Женщина-Кошка. Даже полиции во главе с недавно назначенным комиссаром Гордоном доверять нельзя.  Чтобы разрешить загадку, Бэтмену придется заручиться помощью с самой неожиданной стороны. Он возьмет в напарники осиротевшего мальчика, который навсегда изменит его жизнь. Они станут известны как Бэтмен и Робин. Их история перед вами.  Авторы книги – знаменитый тандем лауреатов премии Айснера Джеф Лоэб и Тим Сэйл («Супермен на все времена», «Бэтмен: Долгий Хэллоуин»). Абсолютное издание включает оригинальную серию из 0–13 выпусков, интервью Джефа Лоэба, вступительные статьи Тима Сэйла и сценариста кинотрилогии о Бэтмене Дэвида С. Гойера, а также множество набросков и эскизов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-07","rating":5,"review":"","added":9999163,"hdCover":""},{"id":"098933a","title":"Рик и Морти (сборник)","author":"Зак Горман,Том Фаулер,Памела Рибон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002290906/140/ca1c/__Rik_i_Morti_sbornik.jpg","isbn":"978-5-91339-518-4,  978-5-91339-620-4","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Научная фантастика"],"annotation":"Если вы следите за невероятными приключениями бедолаги Морти и его деда-алкоголика, учёного и по совместительству межгалактического преступника Рика Санчеза и устали ждать выхода третьего сезона, то эта книга определенно поможет вам скоротать время в ожидании. Приготовьтесь к новой порции безумия, но теперь уже в комиксах, потому что таких историй вы ещё не слышали и не видели! Сюжет комикса не дублирует мультсериал и не оставит равнодушным ни одного любителя отборного интеллектуально-трешёвого юмора и научной фантастики.  Книга включает в себя выпуски комиксов #1-15, а также дополнительные материалы, а это около 400 страниц!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":4,"review":"","added":9999162,"hdCover":""},{"id":"0989339","title":"Ходячие мертвецы. Полное собрание. Том 1 (сборник)","author":"Роберт Киркман,Тони Мур,Клифф Ратбёрн,Чарли Адлард","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002853093/140/7b8d/__Hodyachie_mertvetsy._Polnoe_sobranie._Tom_1_sbornik.jpg","isbn":"978-5-91339-677-8","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас на самом деле старался, чтобы получить желаемое? Давно ли кому-то из нас действительно было нужно то, чего мы постоянно хотим? Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришел мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мёртвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мёртвые, мы наконец вынуждены начать жить","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":5,"review":"","added":9999161,"hdCover":""},{"id":"0989338","title":"Отряд самоубийц. Книга 5. Замурованные","author":"Мэтт Киндт,Патрик Зерчер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002112553/140/43e0/__Otryad_samoubijts._Kniga_5._Zamurovannye.jpg","isbn":"978-5-389-12609-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"А ЕСЛИ ОТРЯД САМОУБИЙЦ ОСТАНЕТСЯ ПОСЛЕДНЕЙ КОМАНДОЙ СУПЕРГЕРОЕВ НА ЗЕМЛЕ?  Разумеется, никому и в голову не придет называть Отряд Самоубийц командой супергероев. Эти опасные преступники под руководством Аманды Уоллер по меньшей мере непредсказуемы... А теперь, когда их не сдерживают вживленные бомбы, они и вовсе неуправляемы.  Но нагрянуло ВЕЧНОЕ ЗЛО, все величайшие герои Земли сгинули, и другого выбора не осталось: отныне судьба всего человечества в руках психопатов из Отряда Самоубийц!  Итак, Уоллер отправляет команду, в которую входят Дэдшот, Харли Квинн и Капитан Бумеранг, на новое задание — не дать Мозговику завладеть невообразимым по своей мощи оружием. Но есть проблема: Мозговик собрал собственный Отряд Самоубийц, призвав Пауэр Герл, Сталь и Неизвестного Солдата... и в их сверхспособностях сомневаться не приходится.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":2.5,"review":"","added":9999160,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989337","title":"Отряд Самоубийц. Книга 4. Надзирать и наказывать","author":"Мэтт Киндт,Патрик Зерчер,Алеш Кот","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002050533/140/6c7a/__Otryad_Samoubijts._Kniga_4._Nadzirat_i_nakazyvat.jpg","isbn":"978-5-389-12236-9","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Вернувшись на базу в тюрьме «Белль-Рив» с очередного провального задания, Аманда Уоллер приходит к выводу, что ее спецназ из отбросов и врагов общества нуждается в свежей крови. Ведь ее Отряд Самоубийц не случайно оказался на грани самоуничтожения.  Вместе с кардинальными переменами члены Отряда получают цель, в которую они действительно верят, и нового командира — безбашенного серийного убийцу, с разумом столь же гениальным, сколь и патологическим. Ну а кто еще поднимет командный дух, как не съехавший с катушек душегуб с неисповедимой логикой? Именно такой командир поможет Отряду сплотиться в решении общей задачи. Он незаменим в предстоящих операциях против гигантского трупомонстра, зомбированных анархистов и некоего персонажа из прошлого Аманды Уоллер, которого она не чаяла встретить снова...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-06","rating":2.5,"review":"","added":9999159,"hdCover":""},{"id":"0989336","title":"Боун. Том 6. Пещера старика","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002371859/140/2fc5/Dzheff_Smit__Boun._Tom_6._Peschera_starika.jpg","isbn":"978-5-99065-299-6,  978-5-9906529-3-4","publisher":"Рамона","pubDate":"2017","language":"Русский","series":"Боун/ Bone","genres":["Комиксы","манга","графические романы"],"annotation":"Крысьи создания вторглись в долину, уничтожая все на своем пути. Местные жители во главе с бабушкой Бен и Луцием объединились с воинами Вени-Ян. Укрепившись в пещере Старика, они готовятся дать врагу решающий бой.  Тем временем человек в капюшоне собирается освободить Повелителя Саранчи при помощи жертвоприношения. Осталось лишь поймать саму жертву в лице Фоуни Боуна... или Торн.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":4.5,"review":"","added":9999158,"hdCover":""},{"id":"0989335","title":"Отряд Самоубийц. Книга 3. Смерть - удел слабаков","author":"Адам Гласс,Хенрик Йонссон,Санду Флореа","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001906306/140/d0fb/__Otryad_Samoubijts._Kniga_3._Smert__udel_slabakov.jpg","isbn":"978-5-389-11686-3","publisher":"Азбука","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Смертельная схватка с Регулусом — лидером крупной террористической группировки «Василиск» — изрядно потрепала Отряд Самоубийц. Дэдшот, командир группы, пожертвовал собой ради спасения своей тайной возлюбленной Харли Квинн, в то время как Йо-Йо и Вольтаика уничтожили их же товарищи по команде.  Но некоторые агенты представляют собой слишком ценные кадры, чтобы покоиться с миром. А злодеи вроде Регулуса слишком опасны, чтобы исчезнуть без следа.  Мало того: Харли Квинн предстоит свидание с прежней любовью — дерзким психопатом, известным под именем Джокер. Уже год его считают покойником, однако он возвращается, чтобы вновь бросить вызов Бэтмену... и наказать Харли за неверность. Кто же теперь возглавит Отряд, который в очередной раз собирается из осколков в единое целое?  Автором сборника выступил Адам Гласс (исполнительный продюсер и сценарист телесериала «Сверхъестественное»), художниками — Хенрик Йонссон («Бэтмен: Detective Stories») и Санду Флореа («Лига справедливости»).  В сборник вошли выпуски №№ 14–19, галерея набросков и примечания.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2.5,"review":"","added":9999157,"hdCover":""},{"id":"0989334","title":"Отряд Самоубийц. Книга 2. Восход Василиска","author":"Адам Гласс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001572262/140/f03d/Adam_Glass__Otryad_Samoubijts._Kniga_2._Voshod_Vasiliska.jpg","isbn":"978-5-389-11191-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2015","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Пока выжившие члены оперативной группы Икс, также известной под названием «Отряд Самоубийц», зализывают раны после провальной операции в Готэме, становится очевидным то, что до сих пор зрело подобно гнойному нарыву — в их рядах предатель! Взращенный и обученный Регулусом, предводителем тайной организации «Василиск», диверсант получает приказ убить Аманду Уоллер и разоблачить Отряд. Неужели это Харли Квинн, сумасшедшая подружка Джокера, чье раздвоение личности уже само по себе представляет угрозу для команды? Или, быть может, это Дэдшот, чьи суицидальные порывы мог использовать в своих целях Регулус?  С предателем на борту, Отряд отправляется на особое задание — захват Митча Шелли, Воскресшего, что в свою очередь, является частью грандиозного плана Аманды Уоллер по полному искоренению организации «Василиск»!  В издание вошел стартовый выпуск № 0, проливающий свет на таинственную личность Аманды Уоллер и истинные причины ее давней вражды с Регулусом.  ОТРЯД САМОУБИЙЦ: ВОСХОД ВАСИЛИСКА включает выпуски № 0 и № 8 — 13 «Отряда Самоубийц» и выпуск № 9 «Воскресший». Это дерзкая и кипящая энергией история, рассказанная Адамом Глассом (исполнительный продюсер и сценарист телесериала «Сверхъестественное») и запечатленная в иллюстрациях Фернандо Дагнино («Action Comics») и других художников.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2,"review":"","added":9999156,"hdCover":""},{"id":"0989333","title":"Отряд самоубийц. Книга 1. Пинок в зубы","author":"Адам Гласс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001516660/140/8908/Adam_Glass__Otryad_samoubijts._Kniga_1._Pinok_v_zuby.jpg","isbn":"978-5-389-10768-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2016","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Что такое Отряд самоубийц? Суперзлодеи, завербованные в тюрьмах и отправленные на секретное, смертельно опасное задание, за которое обещано досрочное освобождение. В шеях у них нанобомбы, удерживающие преступников на коротком поводке. Любым из них пожертвуют, не раздумывая. За это никто не будет призван к ответу. И жестокость и разрушения – всего лишь детали очередного рабочего дня.  Первое задание Отряда сведет вместе шестерых – Дэдшота, Харли Квинн, Эль Дьябло, Вольтаика, Черного Паука и Короля-Акулу, - которым будет противостоять 60 000 крайне опасных врагов. Контролирующая Отряд хладнокровная Аманда Уоллер ведет свою банду убийц от задания к заданию, стремясь предотвратить угрозу мирового масштаба, которую могут остановить только эти негодяи… если, конечно, прежде не перебьют друг друга.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2017-05","rating":2.5,"review":"","added":9999155,"hdCover":""}]');
